final:
module RefModule(
		input   	    sel,
		input 		data_in,
		output  reg	data_out,		
		input 		clk,
		input 		rst

	);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge clk , posedge rst or posedge dbg_halt)
       if(rst)
	      data_out<=0;
      else if(sel)
	      data_out<=data_in;

endmodule
